const SparqlLanguage = LRLanguage.define({
    parser: parser.configure({
        props: [
            styleTags({
                Comment: tags.comment,
                // Query type and clause keywords
                "BASE PREFIX SELECT CONSTRUCT DESCRIBE ASK WHERE DISTINCT REDUCED FROM NAMED": tags.keyword,
                // Graph pattern keywords
                "UNION OPTIONAL MINUS GRAPH SERVICE SILENT FILTER BIND AS VALUES UNDEF": tags.keyword,
                // Solution modifier keywords
                "GROUP BY HAVING ORDER ASC DESC LIMIT OFFSET": tags.keyword,
                // Update operation keywords
                "LOAD INTO TO CLEAR DROP CREATE ADD MOVE COPY INSERT DATA DELETE WITH DEFAULT ALL USING": tags.keyword,
                // Built-in function keywords
                "STR LANG LANGMATCHES DATATYPE BOUND IRI URI BNODE RAND ABS CEIL FLOOR ROUND": tags.keyword,
                "CONCAT STRLEN UCASE LCASE ENCODE_FOR_URI CONTAINS STRSTARTS STRENDS STRBEFORE STRAFTER": tags.keyword,
                "YEAR MONTH DAY HOURS MINUTES SECONDS TIMEZONE TZ NOW UUID STRUUID": tags.keyword,
                "MD5 SHA1 SHA256 SHA384 SHA512 COALESCE IF STRLANG STRDT SAMETERM": tags.keyword,
                "ISIRI ISURI ISBLANK ISLITERAL ISNUMERIC EXISTS NOT IN SUBSTR REPLACE REGEX": tags.keyword,
                // Aggregate function keywords
                "COUNT SUM MIN MAX AVG SAMPLE GROUP_CONCAT SEPARATOR": tags.keyword,
                "Var ObjectListPath/..": tags.variableName,
                String: tags.string,
                Integer: tags.integer,
                "Double Decimal": tags.float,
                "{ }": tags.brace,
                Langstag: tags.annotation,
                "TRUE FALSE": tags.bool,
                "VerbPath Namespace IriRef": tags.namespace,
                "Iri": tags.url,
                "RDFLiteral/Iri": tags.typeName,
            }),
            foldNodeProp.add({
                GroupGraphPattern: foldInside,
                QuadData: foldInside,
                // +7 skips the leading keyword ("PREFIX " or "BASE   ") so the fold starts after it
                Prologue(tree) { return { from: tree.from + 7, to: tree.to }; }
            }),
        ]
    }),
});
function sparql() {
    return new LanguageSupport(SparqlLanguage);
}

export { SparqlLanguage, sparql };
